let raw = $('AI Agent').first().json.output || '';
let text = typeof raw === 'string' ? raw : (raw.output || JSON.stringify(raw));
// Strip n8n langchain agent tool-trace leakage. The ToolsAgent V3
// sometimes prefixes/inlines '[Used tools: Tool: foo, Input: ..., Result: ...]'
// into its final text output. Those traces must never reach the fan.
text = text.replace(/\[Used tools?: [^\]]*?\]\s*/gs, '');
// Strip any leading whitespace left behind
text = text.replace(/^\s+/, '').replace(/\s+$/, '');
// Split on blank lines (one or more newlines with only whitespace between)
let parts = text.split(/\n\s*\n+/).map(s => s.trim()).filter(Boolean);
// If the agent forgot to use blank-line splits, fall back to a single bubble
if (!parts.length) parts = [text.trim()];
// Cap at 6 bubbles to match ManyChat's AI > Answer 1..6 fields
if (parts.length > 6) {
  const tail = parts.slice(5).join('\n\n');
  parts = parts.slice(0, 5).concat([tail]);
}
const fields = parts.map((value, i) => ({ field_name: 'AI > Answer ' + (i + 1), field_value: value }));
return [{ json: {
  subscriber_id: $('Webhook').first().json.body.session_id,
  fields,
  texts: parts,
  combined: parts.join('\n\n'),
} }];
